9707 static void setLimitsForBinOp(const BinaryOperator &BO, APInt &Lower,
9708                               APInt &Upper, const InstrInfoQuery &IIQ,
9709                               bool PreferSignedRange) {
9710   unsigned Width = Lower.getBitWidth();
9711   const APInt *C;
9712   switch (BO.getOpcode()) {
9713   case Instruction::Add:
9714     if (match(BO.getOperand(1), m_APInt(C)) && !C->isZero()) {
9715       bool HasNSW = IIQ.hasNoSignedWrap(&BO);
9716       bool HasNUW = IIQ.hasNoUnsignedWrap(&BO);
9717 
9718       // If the caller expects a signed compare, then try to use a signed range.
9719       // Otherwise if both no-wraps are set, use the unsigned range because it
9720       // is never larger than the signed range. Example:
9721       // "add nuw nsw i8 X, -2" is unsigned [254,255] vs. signed [-128, 125].
9722       if (PreferSignedRange && HasNSW && HasNUW)
9723         HasNUW = false;
9724 
9725       if (HasNUW) {
9726         // 'add nuw x, C' produces [C, UINT_MAX].
9727         Lower = *C;
9728       } else if (HasNSW) {
9729         if (C->isNegative()) {
9730           // 'add nsw x, -C' produces [SINT_MIN, SINT_MAX - C].
9731           Lower = APInt::getSignedMinValue(Width);
9732           Upper = APInt::getSignedMaxValue(Width) + *C + 1;
9733         } else {
9734           // 'add nsw x, +C' produces [SINT_MIN + C, SINT_MAX].
9735           Lower = APInt::getSignedMinValue(Width) + *C;
9736           Upper = APInt::getSignedMaxValue(Width) + 1;
9737         }
9738       }
9739     }
